/// </summary>
/// <param name = "_custPaymIntegrationHistory">ETGCustPaymIntegrationHistory _custPaymIntegrationHistory</param>
/// <returns>ETGCustPaymPostedBusinessEvent</returns>
public static ETGCustPaymPostedBusinessEvent newFromCustPaymIntegrationHistory(ETGCustPaymIntegrationHistory _custPaymIntegrationHistory)
{
    var businessEvent =  new ETGCustPaymPostedBusinessEvent();
    businessEvent.parmCustPaymIntegrationHistory(_custPaymIntegrationHistory);
